// // This module decrements a 4-bit binary counter on each positive edge of the clk signal and resets to 16 when the rst_n signal is active low.
module binary_counter(
    input clk,
    input rst_n,
    output reg [3:0] count
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        count <= 0;
    else
        count <= count + 1;
end

endmodule
